import { PinMethods } from '../../screens/FirstAccess/Models';

import createReducer from '../store/createReducer';

/**
 * Types
 */
export const Types = {
  FORGOT_SMS_REQUEST: 'FORGOT_SMS_REQUEST',
  RESPONSE_SMS: 'RESPONSE_SMS',
  CLEAR_LOADING: 'CLEAR_LOADING',

  PINSPP_SMS_REQUEST: 'PINSPP_SMS_REQUEST',
  PINSPP_SMS_RESPONSE: 'PINSPP_SMS_RESPONSE',
  PINSPP_GET_VALIDATE_PIN: 'PINSPP_GET_VALIDATE_PIN',
  PINSPP_FAILED_PIN: 'PINSPP_FAILED_PIN',
  PINSPP_RESPONSE_PIN: 'PINSPP_RESPONSE_PIN',
  PINSPP_RESPONSE_PIN_USER_EXISTS: 'PINSPP_RESPONSE_PIN_USER_EXISTS',

  GET_VALIDATE_PIN: 'GET_VALIDATE_PIN',
  RESPONSE_PIN: 'RESPONSE_PIN',
  FAILED_PIN: 'FAILED_PIN',

  GET_CHANGE_PASSWORD: 'GET_CHANGE_PASSWORD',
  SUCCESS_CHANGE_PASSWORD: 'SUCCESS_CHANGE_PASSWORD',
  FAILED_CHANGE_PASSWORD: 'FAILED_CHANGE_PASSWORD',

  SET_MODAL_CODE: 'SET_MODAL_CODE',
  SET_STEP: 'SET_STEP',
  SHOW_LOADING: 'SHOW_LOADING',
  CLEAR: 'CLEAR',

  REQUEST_USER_PIN_METHODS: 'REQUEST_USER_PIN_METHODS',
  SUCCESS_USER_PIN_METHODS: 'SUCCESS_USER_PIN_METHODS',
  FAILED_USER_PIN_METHODS: 'FAILED_USER_PIN_METHODS',
  CLEAR_USER_PIN_METHODS: 'CLEAR_USER_PIN_METHODS',
};

/**
 * Initial State
 */
interface IDados {
  pedido: string;
  data: string;
  identificadorStatus: number;
  idVoucher: string;
}

interface InitialState {
  dados: IDados;
  isLoadingEmail: boolean;
  isLoadingSMS: boolean;
  isLoading: boolean;
  success: boolean;
  errorPin: boolean;
  errorPinSPP: boolean;
  step: number;
  modalCode: number;
  hasAccountCreditCard: boolean;
  activateDevice: boolean;
  hsacc: string;
  name: string;
  isLoadingPinMethods: boolean;
  availablePinAuthMethods: Array<keyof typeof PinMethods>;
  document: string;
}

export type State = InitialState;

export const initialState: InitialState = {
  dados: {} as IDados,
  isLoadingEmail: false,
  isLoadingSMS: false,
  isLoading: false,
  success: false,
  errorPin: false,
  errorPinSPP: false,
  modalCode: 0,
  step: 1,
  hasAccountCreditCard: false,
  hsacc: '',
  activateDevice: false,
  name: '',
  availablePinAuthMethods: [],
  isLoadingPinMethods: false,
  document: '',
};

/**
 * Reducers
 */
export const forgotReducer = createReducer(initialState, {
  [Types.FORGOT_SMS_REQUEST](
    state: InitialState,
    { isPhone }: { isPhone: boolean },
  ) {
    return {
      ...state,
      isLoadingSMS: !!isPhone,
      isLoadingEmail: !isPhone,
      hasAccountCreditCard: false,
      hsacc: undefined,
    };
  },
  [Types.CLEAR_LOADING](state: InitialState) {
    return {
      ...state,
      isLoadingSMS: false,
      isLoadingEmail: false,
      isLoading: false,
    };
  },
  [Types.SHOW_LOADING](state: InitialState) {
    return {
      ...state,
      isLoadingSMS: false,
      isLoadingEmail: false,
      isLoading: true,
    };
  },
  [Types.RESPONSE_SMS](state: InitialState) {
    return {
      ...state,
      isLoadingSMS: false,
      isLoadingEmail: false,
    };
  },
  [Types.GET_VALIDATE_PIN](state: InitialState) {
    return {
      ...state,
      errorPin: false,
      isLoading: true,
    };
  },
  [Types.RESPONSE_PIN](
    state: InitialState,
    {
      hasAccountCreditCard,
      hsacc,
      activateDevice,
    }: {
      hasAccountCreditCard?: boolean;
      hsacc?: string;
      activateDevice: boolean;
    },
  ) {
    return {
      ...state,
      hsacc,
      errorPin: false,
      isLoading: false,
      hasAccountCreditCard: hasAccountCreditCard ?? false,
      activateDevice,
    };
  },
  [Types.PINSPP_SMS_REQUEST](
    state: InitialState,
    { isPhone }: { isPhone: boolean },
  ) {
    return {
      ...state,
      isLoadingSMS: !!isPhone,
      isLoadingEmail: !isPhone,
    };
  },
  [Types.PINSPP_RESPONSE_PIN_USER_EXISTS](state: InitialState) {
    return {
      ...state,
      errorPinSPP: false,
      isLoading: false,
    };
  },
  [Types.PINSPP_RESPONSE_PIN](
    state: InitialState,
    {
      dados,
    }: {
      dados: IDados;
    },
  ) {
    return {
      ...state,
      dados,
      errorPinSPP: false,
      isLoading: false,
    };
  },
  [Types.PINSPP_GET_VALIDATE_PIN](state: InitialState) {
    return {
      ...state,
      errorPin: false,
      isLoading: true,
    };
  },
  [Types.PINSPP_FAILED_PIN](state: InitialState) {
    return {
      ...state,
      errorPinSPP: true,
      isLoading: false,
    };
  },
  [Types.GET_CHANGE_PASSWORD](state: InitialState) {
    return {
      ...state,
      isLoading: true,
    };
  },
  [Types.FAILED_PIN](state: InitialState) {
    return {
      ...state,
      errorPin: true,
      isLoading: false,
    };
  },
  [Types.SET_STEP](state: InitialState, { step }: { step: number }) {
    return {
      ...state,
      step,
    };
  },
  [Types.CLEAR](state: InitialState) {
    return {
      ...state,
      dados: {} as IDados,
      isLoadingEmail: false,
      isLoadingSMS: false,
      isLoading: false,
      success: false,
      errorPin: false,
      errorPinSPP: false,
      modalCode: 0,
      step: 1,
      availablePinAuthMethods: [],
      isLoadingPinMethods: false,
    };
  },
  [Types.SET_MODAL_CODE](
    state: InitialState,
    { modalCode }: { modalCode: number },
  ) {
    return {
      ...state,
      modalCode,
    };
  },
  [Types.REQUEST_USER_PIN_METHODS](
    state: InitialState,
    { document }: { document: string },
  ) {
    return {
      ...state,
      isLoadingPinMethods: true,
      document,
    };
  },
  [Types.SUCCESS_USER_PIN_METHODS](
    state: InitialState,
    {
      availablePinAuthMethods,
    }: { availablePinAuthMethods: Array<keyof typeof PinMethods> },
  ) {
    return {
      ...state,
      availablePinAuthMethods,
      isLoadingPinMethods: false,
    };
  },
  [Types.CLEAR_USER_PIN_METHODS](state: InitialState) {
    return {
      ...state,
      availablePinAuthMethods: [],
    };
  },
  [Types.FAILED_USER_PIN_METHODS](state: InitialState) {
    return {
      ...state,
      isLoadingPinMethods: false,
    };
  },
});

/**
 * Actions
 */
export const Creators = {
  requestForgotSMS: (data: {
    document: string;
    isPhone: boolean;
    isAgain?: boolean;
    activateDevice?: number;
  }) => ({
    type: Types.FORGOT_SMS_REQUEST,
    document: data.document,
    isPhone: data.isPhone,
    isAgain: data.isAgain,
    activateDevice: data.activateDevice,
  }),
  pinSPPRequestSMS: (data: { document: string; phone: string }) => ({
    type: Types.PINSPP_SMS_REQUEST,
    document: data.document,
    phone: data.phone,
  }),
  pinSPPfailedPin: () => ({
    type: Types.PINSPP_FAILED_PIN,
  }),
  responseForgotSMS: (phone?: boolean) => ({
    type: Types.RESPONSE_SMS,
    phone,
  }),
  clearLoading: () => ({
    type: Types.CLEAR_LOADING,
  }),
  showLoading: () => ({
    type: Types.SHOW_LOADING,
  }),
  getValidatePin: (data: {
    document: string;
    pin: string;
    activateDevice?: number;
  }) => ({
    type: Types.GET_VALIDATE_PIN,
    document: data.document,
    pin: data.pin,
    activateDevice: data.activateDevice,
  }),
  getValidatePinSPP: (data: {
    document: string;
    pin: string;
    phone: string;
    activateDevice?: number;
    name: string;
  }) => ({
    type: Types.PINSPP_GET_VALIDATE_PIN,
    document: data.document,
    phone: data.phone,
    pin: data.pin,
    activateDevice: data.activateDevice,
    name: data.name,
  }),
  responseValidatePinSPP: (dados: {
    pedido: string;
    data: string;
    identificadorStatus: number;
    idVoucher: string;
  }) => ({
    type: Types.PINSPP_RESPONSE_PIN,
    dados,
  }),
  responseValidatePinSPPUserExists: () => ({
    type: Types.PINSPP_RESPONSE_PIN_USER_EXISTS,
  }),
  responseValidatePin: (
    hasAccountCreditCard?: boolean,
    hsacc?: string,
    activateDevice?: boolean,
  ) => ({
    type: Types.RESPONSE_PIN,
    hasAccountCreditCard,
    hsacc,
    activateDevice: activateDevice ?? false,
  }),
  failedPin: () => ({
    type: Types.FAILED_PIN,
  }),
  getChangePassword: (cpf: string, pin: string, senhaNova: string) => ({
    type: Types.GET_CHANGE_PASSWORD,
    cpf,
    pin,
    senhaNova,
  }),
  setStep: (step: number) => ({
    type: Types.SET_STEP,
    step,
  }),
  clearForgotPasswordReducer: () => ({
    type: Types.CLEAR,
  }),
  setModalCode: (modalCode: number) => ({
    type: Types.SET_MODAL_CODE,
    modalCode,
  }),
  getPinMethods: (document: string) => ({
    type: Types.REQUEST_USER_PIN_METHODS,
    document,
  }),
  setPinMethods: (availablePinAuthMethods: Array<keyof typeof PinMethods>) => ({
    type: Types.SUCCESS_USER_PIN_METHODS,
    availablePinAuthMethods,
  }),
  clearPinMethods: () => ({
    type: Types.CLEAR_USER_PIN_METHODS,
  }),
};

export default forgotReducer;

