import createReducer from '~/redux/store/createReducer';

/**
 * Types
 */
export const Types = {
  REQUEST_DEVICES: 'security/requestDevices',
  SUCCESS_DEVICES: 'security/successDevices',
  DISCONNECT_DEVICE: 'security/disconnectDevice',
  FAILED: 'security/failed',
  CLEAR: 'security/clear',
  REQUEST_REGISTER_DEVICE: 'security/requestRegisterDevice',
  SUCCESS_REGISTER_DEVICE: 'security/successRegisterDevice',
  FAILED_REGISTER_DEVICE: 'security/failedRegisterDevice',
};
/**
 * Initial State
 */
interface InitialState {
  isLoading: boolean;
  devices: Array<{
    UUID: string;
    name: string;
    enabled: boolean;
    latitude?: string;
    longitude?: string;
    lastUpdate: string;
    registerDate: string;
    city?: string;
  }>;
  loadingRegister: boolean;
}

export type State = InitialState;

export const initialState: InitialState = {
  isLoading: true,
  devices: [],
  loadingRegister: false,
};

/**
 * Reducers
 */
export const securityReducer = createReducer(initialState, {
  [Types.REQUEST_DEVICES](state: State) {
    return {
      ...state,
      devices: [],
      isLoading: true,
    };
  },
  [Types.SUCCESS_DEVICES](state: State, { devices }: { devices: State['devices'] }) {
    return {
      ...state,
      devices,
      isLoading: false,
    };
  },
  [Types.DISCONNECT_DEVICE](state: State) {
    return {
      ...state,
      isLoading: true,
    };
  },
  [Types.FAILED](state: State) {
    return {
      ...state,
      isLoading: false,
    };
  },
  [Types.CLEAR]() {
    return {
      ...initialState,
    };
  },
  [Types.REQUEST_REGISTER_DEVICE](state: State) {
    return {
      ...state,
      loadingRegister: true
    }
  },
  [Types.SUCCESS_REGISTER_DEVICE](state: State) {
    return {
      ...state,
      loadingRegister: false,
    }
  },
  [Types.FAILED_REGISTER_DEVICE](state: State) {
    return {
      ...state,
      loadingRegister: false,
    }
  }
});
/**
 * Actions
 */
export const Creators = {
  requestDevices: () => ({
    type: Types.REQUEST_DEVICES,
  }),
  success: (devices: State['devices']) => ({
    type: Types.SUCCESS_DEVICES,
    devices,
  }),
  disconnectDevice: (uuid: string) => ({
    type: Types.DISCONNECT_DEVICE,
    uuid,
  }),
  fail: () => ({
    type: Types.FAILED,
  }),
  clearSecurity: () => ({
    type: Types.CLEAR,
  }),
  requestRegisterDevice: ({cpf, pin} : { cpf: string; pin: string; }) => ({
    type: Types.REQUEST_REGISTER_DEVICE,
    cpf,
    pin,
  }),
  successRegisterDevice: () => ({
    type: Types.SUCCESS_REGISTER_DEVICE,
  }),
  failedRegisterDevice: () => ({
    type: Types.FAILED_REGISTER_DEVICE,
  })
};
/**/
export default securityReducer;

import createReducer from '~/redux/store/createReducer'

/**
 * Types
 */
export const Types = {
  GET: 'updatePassword/get',
  SUCESS: 'updatePassword/sucess',
  FAILED: 'updatePassword/failed',
  CLEAR: 'updatePassword/clear',
}
/**
 * Initial State
 */
interface initialStateProps {
  loading: boolean
  error: boolean
  data: string | boolean | number
  updatePasswordSuccess: boolean;
}

export const initialState: initialStateProps = {
  loading: false,
  error: false,
  data: '',
  updatePasswordSuccess: false,
}

/**
 * Reducers
 */
export const updatePersonalPasswordReducer = createReducer(initialState, {
  [Types.GET](state: initialStateProps) {
    return {
      ...state,
      loading: true,
      updatePasswordSuccess: false,
    }
  },
  [Types.SUCESS](state: initialStateProps, { data }: any) {
    return {
      ...state,
      data,
      loading: false,
      error: false,
      updatePasswordSuccess: true,
    }
  },
  [Types.FAILED](state: initialStateProps) {
    return {
      ...state,
      loading: false,
      error: true,
      updatePasswordSuccess: false,
    }
  },
  [Types.CLEAR](state: initialStateProps) {
    return {
      ...state,
      ...initialState,
    };
  },
})
/**
 * Actions
 */
export const Creators = {
  getUpdatePersonalPassword: (senhaAtual: string, senhaNova: string) => ({
    type: Types.GET,
    senhaAtual,
    senhaNova,
  }),
  successUpdatePersonalPassword: (data: number) => ({
    type: Types.SUCESS,
    data,
  }),
  failedUpdatePersonalPassword: () => ({
    type: Types.FAILED,
  }),
  clearUpdatePersonalPassword: () => ({
    type: Types.CLEAR,
  }),
}
/**/
export default updatePersonalPasswordReducer

import createReducer from '~/redux/store/createReducer'

export const types = {
  REGISTER_ORDER: 'REGISTER_ORDER',
  REGISTER_ORDER_SUCCESS: 'REGISTER_ORDER_SUCCESS',
  REGISTER_ORDER_FAIL: 'REGISTER_ORDER_FAIL',
  UPDATE_USER_ACCESS: 'UPDATE_USER_ACCESS',
  UPDATE_USER_ACCESS_SUCCESS: 'UPDATE_USER_ACCESS_SUCCESS',
  UPDATE_USER_ACCESS_FAIL: 'UPDATE_USER_ACCESS_FAIL',
  CLEAR_SPPAY: 'CLEAR_SPPAY',
  GET_VALUES_SPPAY: 'GET_VALUES_SPPAY',
  VALUES_SPPAY_SUCCESS: 'VALUES_SPPAY_SUCCESS',
  VALUES_SPPAY_FAIL: 'VALUES_SPPAY_FAIL',
  PAYMENT_ORDER: 'PAYMENT_ORDER',
  PAYMENT_ORDER_SUCCESS: 'PAYMENT_ORDER_SUCCESS',
  PAYMENT_ORDER_FAIL: 'PAYMENT_ORDER_FAIL',
  ADD_ADDRESS: 'ADD_ADDRESS',
  GET_VOUCHER: 'GET_VOUCHER',
  SUCCESS_VOUCHER: 'SUCCESS_VOUCHER',
  REQUEST_CHANGE_DEVICE: 'changeDevice/request',
  SUCCESS_CHANGE_DEVICE: 'changeDevice/success',
  FAIL_CHANGE_DEVICE: 'changeDevice/fail',
}

interface InitialState {
  isLoadingRegister: boolean
  isFailRegister: boolean
  dataRegisterError: any
  isLoadingUpdateUserAccess: boolean
  isFailUpdateUserAccess: boolean
  userAccessUpdateError: any
  data: any
  isLoadingValues: boolean
  isFailValues: boolean
  values: any
  valuesError: any
  isLoadingPayment: boolean
  isFailPayment: boolean
  paymentError: any
  step: number
  address: any
  voucher: any
  isLoadingChangeDevice: boolean
}
export type State = InitialState

export const initialState: State = {
  isLoadingRegister: false,
  isFailRegister: false,
  dataRegisterError: '',
  isLoadingUpdateUserAccess: false,
  isFailUpdateUserAccess: false,
  userAccessUpdateError: '',
  data: '',
  isLoadingValues: false,
  isFailValues: false,
  values: '',
  valuesError: '',
  isLoadingPayment: false,
  isFailPayment: false,
  paymentError: '',
  step: 0,
  address: '',
  voucher: '',
  isLoadingChangeDevice: false,
}

export const sppayReducer = createReducer(initialState, {
  [types.REGISTER_ORDER](state: State) {
    return {
      ...state,
      isLoadingRegister: true,
      isFailRegister: false,
    }
  },
  [types.REGISTER_ORDER_SUCCESS](state: State, action: any) {
    return {
      ...state,
      isLoadingRegister: false,
      isFailRegister: false,
      data: action.data,
    }
  },
  [types.REGISTER_ORDER_FAIL](state: State, action: any) {
    return {
      ...state,
      isLoadingRegister: false,
      isFailRegister: true,
      dataRegisterError: action.data,
    }
  },
  [types.UPDATE_USER_ACCESS](state: State) {
    return {
      ...state,
      isLoadingUpdateUserAccess: true,
      isFailUpdateUserAccess: false,
    }
  },
  [types.UPDATE_USER_ACCESS_SUCCESS](state: State, action: any) {
    return {
      ...state,
      isLoadingUpdateUserAccess: false,
      isFailUpdateUserAccess: false,
      data: action.data,
    }
  },
  [types.UPDATE_USER_ACCESS_FAIL](state: State, action: any) {
    return {
      ...state,
      isLoadingUpdateUserAccess: false,
      isFailUpdateUserAccess: true,
      userAccessUpdateError: action.data,
    }
  },
  [types.GET_VALUES_SPPAY](state: State) {
    return {
      ...state,
      isLoadingValues: true,
      isFailValues: false,
    }
  },
  [types.VALUES_SPPAY_SUCCESS](state: State, action: any) {
    return {
      ...state,
      isLoadingValues: false,
      isFailValues: false,
      values: action.data,
      valuesError: '',
    }
  },
  [types.VALUES_SPPAY_FAIL](state: State, action: any) {
    return {
      ...state,
      isLoadingValues: false,
      isFailValues: true,
      values: '',
      valuesError: action.data,
    }
  },
  [types.PAYMENT_ORDER](state: State, action: any) {
    return {
      ...state,
      isLoadingPayment: true,
      isFailPayment: false,
      step: action?.data?.step || 1,
    }
  },
  [types.PAYMENT_ORDER_SUCCESS](state: State, action: any) {
    return {
      ...state,
      isLoadingPayment: false,
      isFailPayment: false,
      data: action.data,
      step: 0,
    }
  },
  [types.PAYMENT_ORDER_FAIL](state: State, action: any) {
    return {
      ...state,
      isLoadingPayment: false,
      isFailPayment: true,
      paymentError: action.data,
      step: 0,
    }
  },
  [types.ADD_ADDRESS](state: State, action: any) {
    return {
      ...state,
      address: action.data,
    }
  },
  [types.SUCCESS_VOUCHER](state: State, action: any) {
    return {
      ...state,
      voucher: action.data,
    }
  },
  [types.CLEAR_SPPAY](state: State) {
    return {
      ...state,
      ...initialState,
      voucher: state.voucher,
    }
  },
  [types.REQUEST_CHANGE_DEVICE](state: State) {
