import createReducer from '~/redux/store/createReducer'
import data from '~/screens/BuySPPAY/data'

/**
 * Types
 */
export const Types = {
  GET_MONITORINGSPP: 'GET_MONITORINGSPP',
  SUCCESS_MONITORINGSPP: 'SUCCESS_MONITORINGSPP',
  FAILED_MONITORINGSPP: 'FAILED_MONITORINGSPP',
  LOADING_CLEAR: 'LOADING_CLEAR',
}
/**
 * Initial State
 */
interface initialStateProps {
  isTrue: boolean
  loading: boolean
  title: string

}

export type State = initialStateProps;

export const initialState: initialStateProps = {
  isTrue: true,
  loading: true,
  title: ''
}

/**
 * Reducers
 */
export const statusMonitoringSPP = createReducer(initialState, {
  [Types.GET_MONITORINGSPP](state: initialStateProps) {
    return {
      ...state,
    }
  },
  [Types.SUCCESS_MONITORINGSPP](state: initialStateProps, action: {data: string}) {
    return {
      ...state,
      isTrue: true,
      title: action.data,
    }
  },
  [Types.FAILED_MONITORINGSPP](state: initialStateProps, action: {data: string}) {
    return {
      ...state,
      isTrue: false,
      title: action.data,
    }
  },
  [Types.LOADING_CLEAR](state: initialStateProps, action: {loading: boolean}) {
    return {
      ...state,
      loading: action.loading,
    }
  },
})
/**
 * Actions
 */
export const Creators = {
  getMonitoringSPP: () => ({
    type: Types.GET_MONITORINGSPP,
  }),
  successMonitoringSPP: (data: string) => ({
    type: Types.SUCCESS_MONITORINGSPP,
    data,
  }),
  failedMonitoringSPP: (data: string) => ({
    type: Types.FAILED_MONITORINGSPP,
    data,
  }),
  loadingClear: (loading: boolean) => ({
    type: Types.LOADING_CLEAR,
    loading,
  })
}
/**/
export default statusMonitoringSPP

