import { CommonActions } from '@react-navigation/native';

import { put, call } from '@redux-saga/core/effects';

import {api} from '@semparar/mf-app-user';

import { Creators as ExampleActions } from '~/redux/ducks/example';

import { failureMessage } from './functions';

import { navigatorRef } from '~/routes/navigation';

export function* exampleRequest({
  data: { test1, test2 },
}: {
  data: { test1: string; test2: string };
}) {
  try {
    const payload: {
      test1: string;
      test2: string;
    } = {
      test1,
      test2,
    };
    const response = yield call(api.post, '/example', payload);
    const data = response?.data;
    switch (data?.status?.codigoRetorno) {
      case 0:
        yield put(ExampleActions.success(data?.dados?.mensagem));

        navigatorRef.current?.dispatch(
          CommonActions.reset({
            index: 0,
            routes: [{ name: 'SuccessExample' }],
          })
        );

        break;

      default:
        yield put(ExampleActions.fail());
        failureMessage();
        break;
    }
  } catch (error) {
    yield put(ExampleActions.fail());
    failureMessage();
  }
}

