import React, { useEffect, useState } from 'react';
import Modal from 'react-native-modal';
import { Box, Header as HeaderDS } from '@semparar/design-system-app';

import { PRYMARY_BASE_02, LIGHT_BASE_01, PRYMARY_BASE_01 } from '~/styles/colors';
import Menu from '~/components/Menu';
import { eventScreenViewV2, _event } from '~/constants/functions';

import { PropsView } from './Models';
import { useNavigation } from '@react-navigation/native';
import { CustomerTypes } from '@semparar/mf-app-user';
import { bindActionCreators, Dispatch } from 'redux';
import { connect } from 'react-redux';
import { SafeAreaView, StatusBar, View } from 'react-native';
import normalize from 'react-native-normalize';

export const HEIGHT_HEADER = normalize(92);

const Header: React.FC<PropsView> = ({
  title,
  originRefresh,
  filterName,
  iconFilterName,
  filter,
  isClose,
  onClose,
  navigationFilter,
  isExtractPre,
  semPararPayPure,
  isExtractTrio,
  isExtractPos,
  functionFilter,
  backbutton,
  backPress,
  events,
  typePreManual,
  saldoTrio,
  valueFiring,
  haveTicket,
  isBlocked,
  isolatedHeader,
  bgColor,
}) => {
    const navigation = useNavigation();
    const hasExtractFilter =
        (!!filter || !!navigationFilter) &&
        ((isExtractPre && !semPararPayPure) || isExtractTrio || isExtractPos);

    const [isVisbleMenu, setIsVisibleMenu] = useState(false);

    const _toggleMenu = () => setIsVisibleMenu(!isVisbleMenu);

    const dispatchEventFocus = () => {
        title && eventScreenViewV2(title);
    }

    useEffect(() => {
        navigation.addListener('focus', dispatchEventFocus.bind(this));
        return () => {
            navigation.removeListener('focus', dispatchEventFocus.bind(this));
        }
    }, []);

    const renderHeader = () => {
        return (
            <Box width="100%" bgColor={LIGHT_BASE_01}>
                <HeaderDS
                    title={title}
                    isNewHeader
                    hideLeftIcon={!backbutton}
                    bgColor={LIGHT_BASE_01}
                    titleColor={PRYMARY_BASE_02}
                    iconRight={iconFilterName ?? null}
                    isClose={isClose}
                    onClose={onClose}
                    onPressTextRight={!hasExtractFilter ? navigationFilter : null}
                    textRight={filterName ?? null}
                    isOption={filter || navigationFilter}
                    onPressIconRight={!!hasExtractFilter ? _toggleMenu : functionFilter}
                    onBack={
                        backbutton
                        ? () => {
                            if (!backPress) {
                                if (events) {
                                    _event(...events);
                                }
                                if (originRefresh) {
                                    navigation.navigate('LoginScreen');
                                } else {
                                    navigation.canGoBack() && navigation.goBack();
                                }
                            } else {
                                backPress();
                            }
                        }
                        : null
                    }
                />
                {!!hasExtractFilter ? (
                    <Modal
                        animationIn="slideInRight"
                        animationOut="slideOutRight"
                        isVisible={isVisbleMenu}
                        style={{
                            justifyContent: 'flex-start',
                            alignItems: 'flex-end',
                        }}
                        onBackdropPress={_toggleMenu}>
                        <Menu
                            typePreManual={typePreManual}
                            saldoTrio={saldoTrio}
                            isExtractTrio={isExtractTrio}
                            isExtractPre={isExtractPre}
                            isExtractPos={isExtractPos}
                            navigationFilter={navigationFilter}
                            toggleMenu={_toggleMenu}
                            navigation={navigation}
                            valueFiring={valueFiring}
                            haveTicket={haveTicket}
                            isBlocked={isBlocked}
                        />
                    </Modal>
                ) : null}
            </Box>
        );
    }

    return (
      <>
        {isolatedHeader ? 
            <View style={{ backgroundColor: bgColor ?? LIGHT_BASE_01 }}>
                <StatusBar backgroundColor={PRYMARY_BASE_01} barStyle="light-content" />
                <SafeAreaView
                    style={{
                        flex: 0,
                        backgroundColor: PRYMARY_BASE_01,
                    }}
                />
                {renderHeader()}
            </View>
        : renderHeader()}
      </>
    );
};

const mapStateToProps = ({
    customerReducer,
}: {
    customerReducer: typeof CustomerTypes;
}) => ({
    semPararPayPure: customerReducer?.pay?.isUniqueProduct,
    typePreManual: customerReducer.isPrePaidManual,
    isBlocked: customerReducer.isBlocked,
});

const mapDispatchToProps = (dispatch: Dispatch) => {
    return bindActionCreators(
      {
      },
      dispatch
    );
  };

export default connect(mapStateToProps, mapDispatchToProps)(Header);

