import React from 'react';
import { bindActionCreators, Dispatch } from 'redux';
import { connect } from 'react-redux';
import { CustomerActions } from '@semparar/mf-app-user';
import * as modalActions from '~/redux/actions/modalActions';
import * as statusTagActions from '~/redux/actions/statusTagActions';

import { Props } from './Models';
import ScreenView from './view';

const Screen: React.FC<Props> = ({
  scrollHeader,
  children,
  fixedBottom,
  title,
  bgColor,
  originRefresh,
  filterName,
  iconFilterName,
  filter,
  isClose,
  onClose,
  navigationFilter,
  isExtractPre,
  isExtractTrio,
  isExtractPos,
  functionFilter,
  backbutton,
  backPress,
  events,
  saldoTrio,
  valueFiring,
  haveTicket,
  hasScroll = true,
  loadingComponent,
  modalsComponent,
}) => {
  return (
    <ScreenView
      hasScroll={hasScroll}
      scrollHeader={scrollHeader}
      children={children}
      bgColor={bgColor}
      fixedBottom={fixedBottom}
      title={title}
      originRefresh={originRefresh}
      filterName={filterName}
      iconFilterName={iconFilterName}
      filter={filter}
      isClose={isClose}
      onClose={onClose}
      navigationFilter={navigationFilter}
