import React from 'react';

import { bindActionCreators, Dispatch } from 'redux';
import { connect } from 'react-redux';

import { CommonActions, useNavigation } from '@react-navigation/native';

import { State as ExampleReducerType } from '~/redux/ducks/example';

import { Props } from '../Models/success';

import SuccessView from './view';

const Success: React.FC<Props> = ({ data }) => {
  const navigation = useNavigation();
  const navLogin: () => void = () => {
    navigation.dispatch(
      CommonActions.reset({
        index: 0,
        routes: [{ name: 'Example' }],
      })
    );
  };

  return <SuccessView navigation={navigation} data={data} navLogin={navLogin} />;
};

const mapStateToProps = ({ exampleReducer }: { exampleReducer: ExampleReducerType }) => ({
  data: exampleReducer.data,
});

const mapDispatchToProps = (dispatch: Dispatch) => {
  return bindActionCreators({}, dispatch);
};

export default connect(mapStateToProps, mapDispatchToProps)(Success);

