import * as types from './types'

export function PreResumeRequest(param, indice) {
  return {
    type: types.PRE_RESUME_REQUEST,
    param,
    indice,
  }
}

export function PreResumeSuccess(data) {
  return {
    type: types.PRE_RESUME_SUCCESS,
    data,
  }
}

export function PreResumeNextPageRequest(param, indice) {
  return {
    type: types.PRE_RESUME_NEXT_PAGE_REQUEST,
    param,
    indice
  }
}

export function PreResumeNextPageSuccess(data) {
  return {
    type: types.PRE_RESUME_NEXT_PAGE_SUCCESS,
    data,
  }
}

export function PreResumeFinishRequest() {
  return {
    type: types.PRE_RESUME_FINISH_REQUEST,
  }
}

export function PreResumeFailed(action) {
  return {
    type: types.PRE_RESUME_FAILED,
    action,
  }
}

export function PreSaldoRequest(param) {
  return {
    type: types.PRE_SALDO_REQUEST,
    param,
  }

